override fun onReceive(context: Context, intent: Intent) {
        if (intent.action == Telephony.Sms.Intents.SMS_RECEIVED_ACTION) {
            val messages = Telephony.Sms.Intents.getMessagesFromIntent(intent)
            val db = AppDatabase.getDatabase(context)
            val transactionDao = db.transactionDao()
            val accountDao = db.accountDao()
            val categoryDao = db.categoryDao()

            CoroutineScope(Dispatchers.IO).launch {
                val accounts = accountDao.getAllAccountsOnce()
                val categories = categoryDao.getAllCategoriesOnce()

                for (message in messages) {
                    val body = message.messageBody
                    val date = message.timestampMillis
                    val address = message.originatingAddress

                    SmsParser.parse(body, date, address, accounts, categories)?.let { tx ->
                        try {
                            // Use reconciliation method to allow re-importing if previously deleted
                            transactionDao.insertTransactionWithReconciliation(tx)
                            Log.d(TAG, "Successfully ingested real-time SMS transaction: ${tx.externalId}")
                        } catch (e: Exception) {
                            Log.e(TAG, "Failed to insert SMS transaction. Possible duplicate: ${tx.externalId}", e)
                        }
                    }
                }
            }
        }
    }

